sealed class FfiRegistryException(message: String): kotlin.Exception(message) {
        
        class Registry(message: String) : FfiRegistryException(message)
        
        class Store(message: String) : FfiRegistryException(message)
        
        class NotFound(message: String) : FfiRegistryException(message)
        
        class NotInstalled(message: String) : FfiRegistryException(message)
        
        class Manifest(message: String) : FfiRegistryException(message)
        
    /**
     * The registry knows about this skill but doesn't carry a preview
     * manifest sidecar — typically an index row generated before the
     * sidecar pipeline was introduced. UI should fall back to the
     * lightweight [`FfiBrowseEntry`] fields rather than showing an error.
     */
        class ManifestUnavailable(message: String) : FfiRegistryException(message)
        
        class TrustKey(message: String) : FfiRegistryException(message)
        

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<FfiRegistryException> {
        override fun lift(error_buf: RustBuffer.ByValue): FfiRegistryException = FfiConverterTypeFfiRegistryError.lift(error_buf)
    }
}

/**
 * @suppress
 */
public object FfiConverterTypeFfiRegistryError : FfiConverterRustBuffer<FfiRegistryException> {
    override fun read(buf: ByteBuffer): FfiRegistryException {
        
            return when(buf.getInt()) {
            1 -> FfiRegistryException.Registry(FfiConverterString.read(buf))
            2 -> FfiRegistryException.Store(FfiConverterString.read(buf))
            3 -> FfiRegistryException.NotFound(FfiConverterString.read(buf))
            4 -> FfiRegistryException.NotInstalled(FfiConverterString.read(buf))
            5 -> FfiRegistryException.Manifest(FfiConverterString.read(buf))
            6 -> FfiRegistryException.ManifestUnavailable(FfiConverterString.read(buf))
            7 -> FfiRegistryException.TrustKey(FfiConverterString.read(buf))
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
        
    }

    override fun allocationSize(value: FfiRegistryException): ULong {
        return 4UL
    }

    override fun write(value: FfiRegistryException, buf: ByteBuffer) {
        when(value) {
            is FfiRegistryException.Registry -> {
                buf.putInt(1)
                Unit
            }
            is FfiRegistryException.Store -> {
                buf.putInt(2)
                Unit
            }
            is FfiRegistryException.NotFound -> {
                buf.putInt(3)
                Unit
            }
            is FfiRegistryException.NotInstalled -> {
                buf.putInt(4)
                Unit
            }
            is FfiRegistryException.Manifest -> {
                buf.putInt(5)
                Unit
            }
            is FfiRegistryException.ManifestUnavailable -> {
                buf.putInt(6)
                Unit
            }
            is FfiRegistryException.TrustKey -> {
                buf.putInt(7)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}



sealed class FfiResponse {
    
    data class Text(
        val `body`: kotlin.String) : FfiResponse()
        
    {
        

        companion object
    }
    
    /**
     * `skill_id` is the manifest id of the emitting skill (e.g.
     * `dev.heyari.timer`), used by the frontend to resolve `asset:<path>`
     * references back to the skill's bundle directory. Empty string if
     * the engine couldn't attribute the response to a specific skill
     * (router-direct actions, fallbacks) — treat that as "no bundle,
     * asset references will fail to resolve".
     */
    data class Action(
        val `json`: kotlin.String, 
        val `skillId`: kotlin.String) : FfiResponse()
        
    {
        

        companion object
    }
    
    data class Binary(
        val `mime`: kotlin.String, 
        val `data`: kotlin.ByteArray) : FfiResponse()
        
    {
        

        companion object
    }
    
    /**
     * The engine couldn't match any skill to the input. The host can use
     * this signal to retry the upstream STT (e.g. with a fresh sherpa
     * stream on the buffered audio) before falling back to the apology.
     * `body` carries the apology text the host should say if the retry
     * also fails — kept here so the host doesn't have to hardcode it.
     */
    data class NotUnderstood(
        val `body`: kotlin.String) : FfiResponse()
        
    {
        

        companion object
    }
    

    

    
    


    companion object
}

/**
 * @suppress
 */
public object FfiConverterTypeFfiResponse : FfiConverterRustBuffer<FfiResponse>{
    override fun read(buf: ByteBuffer): FfiResponse {
        return when(buf.getInt()) {
            1 -> FfiResponse.Text(
                FfiConverterString.read(buf),
                )
            2 -> FfiResponse.Action(
                FfiConverterString.read(buf),
                FfiConverterString.read(buf),
                )
            3 -> FfiResponse.Binary(
                FfiConverterString.read(buf),
                FfiConverterByteArray.read(buf),
                )
            4 -> FfiResponse.NotUnderstood(
                FfiConverterString.read(buf),
                )
            else -> throw RuntimeException("invalid enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: FfiResponse) = when(value) {
        is FfiResponse.Text -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterString.allocationSize(value.`body`)
            )
        }
        is FfiResponse.Action -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterString.allocationSize(value.`json`)
                + FfiConverterString.allocationSize(value.`skillId`)
            )
        }
        is FfiResponse.Binary -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterString.allocationSize(value.`mime`)
                + FfiConverterByteArray.allocationSize(value.`data`)
            )
        }
        is FfiResponse.NotUnderstood -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterString.allocationSize(value.`body`)
            )
        }
    }

    override fun write(value: FfiResponse, buf: ByteBuffer) {
        when(value) {
            is FfiResponse.Text -> {
                buf.putInt(1)
                FfiConverterString.write(value.`body`, buf)
                Unit
            }
            is FfiResponse.Action -> {
                buf.putInt(2)
                FfiConverterString.write(value.`json`, buf)
                FfiConverterString.write(value.`skillId`, buf)
                Unit
            }
            is FfiResponse.Binary -> {
                buf.putInt(3)
                FfiConverterString.write(value.`mime`, buf)
                FfiConverterByteArray.write(value.`data`, buf)
                Unit
            }
            is FfiResponse.NotUnderstood -> {
                buf.putInt(4)
                FfiConverterString.write(value.`body`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }
}






/**
 * @suppress
 */
public object FfiConverterOptionalULong: FfiConverterRustBuffer<kotlin.ULong?> {
    override fun read(buf: ByteBuffer): kotlin.ULong? {
        if (buf.get().toInt() == 0) {
            return null
        }
        return FfiConverterULong.read(buf)
    }

    override fun allocationSize(value: kotlin.ULong?): ULong {
        if (value == null) {
            return 1UL
        } else {
            return 1UL + FfiConverterULong.allocationSize(value)
        }
    }

    override fun write(value: kotlin.ULong?, buf: ByteBuffer) {
        if (value == null) {
            buf.put(0)
        } else {
            buf.put(1)
            FfiConverterULong.write(value, buf)
        }
    }
}




